import{_ as e,o as s,c as o,g as t}from"./chunks/framework.CtuiYkcd.js";const N=JSON.parse('{"title":"遐三的序","description":"","frontmatter":{"title":"遐三的序","date":"2014-12-19T01:24:21.990Z","length":"411字","time":"2分钟","aside":false,"hash":-1216746888},"headers":[],"relativePath":"article/遐三的序.md","filePath":"article/遐三的序.md"}'),n={name:"article/遐三的序.md"},_=t("p",null,"遐思笔记从初三毕业那个暑假开始，到如今也一年有余了，而笔记如今已至第三本，却似乎还未对笔记的来历有过介绍，借第三本书肇始，顺便提提遐思笔记的由来。",-1),l=t("p",null,"初三毕业后，总觉得往事太多值得留于纸端，遂提笔叙写初中人事，本欲以拙笔带过小学人情事，谁知初中仍未尽了，后又学业繁杂，搁笔竟成遗恨！",-1),a=t("p",null,"故第一本仅以记初中回忆往事为主，偶有几篇其他附于书末，隔以空白，虽然内容不多，但描写极细，颇为自豪。",-1),c=t("p",null,"第二本用14年爬山纪念品为本，自五月始至十二月终，内容从数学起，杂以哲学、生活、学习探讨外加心情日记若干及道歉信一封。",-1),i=t("p",null,"第二本中，有感而发笔记不少，每日灵感均有记录，加上多年积累形成的价值观与对事物的各方面看法，内容应是较翔实且有价值的。",-1),d=t("p",null,"犹记得在八月至十月有进入创作高峰，午睡时间卧。床写作，空调的凉意与被窝之暖协调恰好，睡前倦意与旁无嘈杂的氛围，拱出了一篇又一篇的泉涌思流，怎一个惬意了得？",-1),r=t("p",null,"放松着实能带来泉涌浪涨之思，不禁满溢而出，妙文成集。",-1),p=t("p",null,"遐思笔记如今以成为我生活的一部分，而写作慢慢成了我表达思想的习惯与爱好。",-1),h=t("p",null,"并愿你我不断多产。",-1),u=[_,l,a,c,i,d,r,p,h];function m(f,$,g,x,B,k){return s(),o("div",null,u)}const P=e(n,[["render",m]]);export{N as __pageData,P as default};
